UPDATE legislacao_mandato_executivo lme
SET
  tipo_relacao = s.tipo_relacao,
  esfera = s.esfera,
  uf_norma = s.uf_norma,
  ementa = s.ementa,
  signatario = s.signatario,
  autoridade_papel = s.autoridade_papel,
  fonte_primaria_url = s.fonte_primaria_url,
  fonte_primaria_titulo = s.fonte_primaria_titulo,
  fonte_tramitacao_url = s.fonte_tramitacao_url,
  identificador_fonte = s.identificador_fonte,
  metadata = s.metadata::jsonb
FROM _seed_tarcisio_sp_legislacao_ampliado_parcial s
JOIN candidatos c ON c.slug = 'tarcisio'
WHERE lme.candidato_id = c.id
  AND lme.tipo_norma = s.tipo_norma
  AND lme.numero = s.numero
  AND lme.ano = s.ano
  AND lme.data_norma = s.data_norma::date;

INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  c.id,
  (
    SELECT hp.id
    FROM historico_politico hp
    WHERE hp.candidato_id = c.id
      AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
      AND (hp.periodo_inicio IS NULL OR hp.periodo_inicio <= s.ano)
      AND (hp.periodo_fim IS NULL OR hp.periodo_fim >= s.ano)
      AND (
        UPPER(COALESCE(hp.estado, '')) = s.uf_norma
        OR hp.cargo ILIKE '%São Paulo%'
        OR hp.cargo ILIKE '%Sao Paulo%'
      )
    ORDER BY
      hp.periodo_inicio DESC NULLS LAST
    LIMIT 1
  ),
  s.tipo_relacao,
  s.esfera,
  s.uf_norma,
  s.tipo_norma,
  s.numero,
  s.ano,
  s.data_norma::date,
  s.ementa,
  s.signatario,
  s.autoridade_papel,
  s.fonte_primaria_url,
  s.fonte_primaria_titulo,
  s.fonte_tramitacao_url,
  s.identificador_fonte,
  s.metadata::jsonb
FROM _seed_tarcisio_sp_legislacao_ampliado_parcial s
JOIN candidatos c ON c.slug = 'tarcisio'
WHERE NOT EXISTS (
  SELECT 1
  FROM legislacao_mandato_executivo lme
  WHERE lme.candidato_id = c.id
    AND lme.tipo_norma = s.tipo_norma
    AND lme.numero = s.numero
    AND lme.ano = s.ano
    AND lme.data_norma = s.data_norma::date
);

DROP TABLE _seed_tarcisio_sp_legislacao_ampliado_parcial;
